onRowSelected:
{{
    GetAssetStatus.run();
    CheckAssetOnSale.run(() => {
        const alreadySold = CheckAssetOnSale.data.length > 0;
        const status = GetAssetStatus.data[0]?.status_name;

        if (alreadySold) {
            showAlert(
                "Asset already on Sales Order: " + CheckAssetOnSale.data[0].sale_ref,
                "warning"
            );
        }
        else if (status !== "Available for Sale") {
            showAlert(
                "Asset not available for sale — current status: " + status,
                "warning"
            );
        }

        storeValue("assetBlocked", false);
        storeValue("reason", "");
    });
}}
